--
-- Table structure for table `route_node_fact`
--

DROP TABLE IF EXISTS `route_node_fact`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `route_node_fact` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `plan_fact_id` bigint NOT NULL COMMENT '关联 route_plan_fact 主键',
  `itinerary_id` bigint DEFAULT NULL COMMENT '关联行程ID',
  `user_id` bigint DEFAULT NULL COMMENT '用户ID',
  `option_key` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所属方案 Key',
  `route_signature` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所属路线签名',
  `step_order` int NOT NULL COMMENT '节点顺序，从 1 开始',
  `poi_id` bigint NOT NULL COMMENT 'POI ID',
  `poi_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'POI 名称快照',
  `category` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'POI 分类快照',
  `district` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '行政区快照',
  `start_time` time DEFAULT NULL COMMENT '计划开始游玩时间',
  `end_time` time DEFAULT NULL COMMENT '计划结束游玩时间',
  `stay_duration` int DEFAULT NULL COMMENT '停留时长，单位分钟',
  `travel_time` int DEFAULT NULL COMMENT '从上一节点到当前节点的通行时间，单位分钟',
  `node_cost` decimal(10,2) DEFAULT NULL COMMENT '当前节点花费',
  `sys_reason` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '系统给出的节点选择理由',
  `operating_status` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '营业状态快照',
  `status_note` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '营业状态说明',
  `create_time` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '写入时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_route_node_plan_step` (`plan_fact_id`,`step_order`),
  KEY `idx_route_node_itinerary_step` (`itinerary_id`,`step_order`),
  KEY `idx_route_node_poi_time` (`poi_id`,`create_time`),
  KEY `idx_route_node_user_time` (`user_id`,`create_time`),
  KEY `idx_route_node_option_key` (`option_key`)
) ENGINE=InnoDB AUTO_INCREMENT=63 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='路线节点明细事实表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `route_node_fact`
--

LOCK TABLES `route_node_fact` WRITE;
/*!40000 ALTER TABLE `route_node_fact` DISABLE KEYS */;
