--
-- Table structure for table `route_plan_fact`
--

DROP TABLE IF EXISTS `route_plan_fact`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `route_plan_fact` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint DEFAULT NULL COMMENT '用户ID，匿名规划可为空',
  `itinerary_id` bigint DEFAULT NULL COMMENT '关联行程ID',
  `plan_source` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '规划来源，如 generate、replan、replace',
  `algorithm_version` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '算法版本号',
  `recall_strategy` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '候选召回/筛选策略标识',
  `raw_candidate_count` int NOT NULL DEFAULT '0' COMMENT '原始候选 POI 数量',
  `filtered_candidate_count` int NOT NULL DEFAULT '0' COMMENT '过滤后的候选 POI 数量',
  `final_candidate_count` int NOT NULL DEFAULT '0' COMMENT '进入最终求解阶段的候选数量',
  `max_stops` int NOT NULL DEFAULT '0' COMMENT '本次规划允许的最大站点数',
  `generated_route_count` int NOT NULL DEFAULT '0' COMMENT '算法生成的候选路线总数',
  `displayed_option_count` int NOT NULL DEFAULT '0' COMMENT '最终展示给用户的方案数',
  `selected_option_key` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '最终选中的方案 Key',
  `selected_route_signature` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '最终路线签名，用于去重与版本比对',
  `total_duration` int DEFAULT NULL COMMENT '总时长，单位分钟',
  `total_cost` decimal(10,2) DEFAULT NULL COMMENT '总花费',
  `total_travel_time` int DEFAULT NULL COMMENT '总通行时间，单位分钟',
  `business_risk_score` int DEFAULT NULL COMMENT '营业状态风险分',
  `theme_match_count` int DEFAULT NULL COMMENT '主题命中数量',
  `route_utility` decimal(12,4) DEFAULT NULL COMMENT '路线综合效用值',
  `selected_route_feature_json` longtext COLLATE utf8mb4_unicode_ci COMMENT 'selected route LTR feature vector JSON',
  `options_feature_json` longtext COLLATE utf8mb4_unicode_ci COMMENT 'candidate options LTR feature vector JSON',
  `trip_date` date DEFAULT NULL COMMENT '出行日期',
  `trip_start_time` time DEFAULT NULL COMMENT '计划开始时间',
  `trip_end_time` time DEFAULT NULL COMMENT '计划结束时间',
  `budget_level` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '预算等级',
  `is_rainy` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否雨天场景',
  `is_night` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否夜游场景',
  `walking_level` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '步行强度等级',
  `companion_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '同行人类型',
  `themes_json` longtext COLLATE utf8mb4_unicode_ci COMMENT '主题偏好 JSON 数组',
  `request_snapshot_json` longtext COLLATE utf8mb4_unicode_ci COMMENT '原始请求快照 JSON',
  `replan_from_itinerary_id` bigint DEFAULT NULL COMMENT '重排来源行程 ID',
  `replace_target_poi_id` bigint DEFAULT NULL COMMENT '被替换的目标 POI ID',
  `replaced_with_poi_id` bigint DEFAULT NULL COMMENT '最终替换成的 POI ID',
  `success_flag` tinyint(1) NOT NULL DEFAULT '1' COMMENT '本次规划是否成功',
  `fail_reason` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '失败原因或未命中的业务提示',
  `planning_started_at` datetime(3) DEFAULT NULL COMMENT '规划开始时间',
  `planning_finished_at` datetime(3) DEFAULT NULL COMMENT '规划结束时间',
  `cost_ms` int DEFAULT NULL COMMENT '规划总耗时，单位毫秒',
  `create_time` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '写入时间',
  PRIMARY KEY (`id`),
  KEY `idx_route_plan_user_time` (`user_id`,`create_time`),
  KEY `idx_route_plan_itinerary` (`itinerary_id`),
  KEY `idx_route_plan_source_time` (`plan_source`,`create_time`),
  KEY `idx_route_plan_trip_date` (`trip_date`),
  KEY `idx_route_plan_success_time` (`success_flag`,`create_time`),
  KEY `idx_route_plan_replace_target` (`replace_target_poi_id`)
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='路线规划事实表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `route_plan_fact`
