DROP TABLE IF EXISTS `saved_itinerary`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `saved_itinerary` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `request_json` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `itinerary_json` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `favorited` tinyint(1) NOT NULL DEFAULT '0',
  `favorite_time` datetime DEFAULT NULL,
  `custom_title` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `share_note` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_public` tinyint(1) NOT NULL DEFAULT '0',
  `node_count` int NOT NULL DEFAULT '0',
  `total_duration` int DEFAULT NULL,
  `total_cost` decimal(10,2) DEFAULT NULL,
  `route_signature` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '社区帖子是否已软删除',
  `deleted_at` datetime DEFAULT NULL COMMENT '删帖时间',
  `deleted_by` bigint DEFAULT NULL COMMENT '删帖执行人',
  `is_global_pinned` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否全站置顶',
  `global_pinned_at` datetime DEFAULT NULL COMMENT '全站置顶时间',
  `global_pinned_by` bigint DEFAULT NULL COMMENT '全站置顶执行人',
  `pinned_comment_id` bigint DEFAULT NULL COMMENT '作者置顶评论 ID',
  PRIMARY KEY (`id`),
  KEY `idx_saved_itinerary_user` (`user_id`),
  KEY `idx_saved_itinerary_public_deleted_updated` (`is_public`,`is_deleted`,`update_time`),
  KEY `idx_saved_itinerary_global_pinned` (`is_global_pinned`,`global_pinned_at`)
) ENGINE=InnoDB AUTO_INCREMENT=76 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Saved itinerary snapshots';
/*!40101 SET character_set_client = @saved_cs_client */;

