--
-- Table structure for table `user_behavior_event`
--

DROP TABLE IF EXISTS `user_behavior_event`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_behavior_event` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint DEFAULT NULL COMMENT '用户ID，匿名行为可为空',
  `session_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '会话ID，用于关联匿名会话',
  `request_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '请求追踪ID',
  `event_type` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '行为类型，如 plan_submit、option_select、replan_click',
  `event_source` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'backend' COMMENT '事件来源，如 backend、frontend、miniprogram',
  `itinerary_id` bigint DEFAULT NULL COMMENT '关联行程ID',
  `poi_id` bigint DEFAULT NULL COMMENT '关联 POI ID',
  `option_key` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联方案 Key',
  `interaction_weight` decimal(8,2) NOT NULL DEFAULT '1.00' COMMENT '行为权重，用于隐式反馈建模',
  `success_flag` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否成功采集/执行',
  `cost_ms` int DEFAULT NULL COMMENT '请求或行为耗时，单位毫秒',
  `request_uri` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '请求 URI',
  `http_method` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'HTTP 方法',
  `client_ip` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '客户端 IP',
  `user_agent` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '客户端 User-Agent',
  `referer` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '来源页面',
  `extra_json` longtext COLLATE utf8mb4_unicode_ci COMMENT '扩展上下文 JSON，如请求参数、失败原因、来源页等',
  `event_time` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '行为发生时间',
  PRIMARY KEY (`id`),
  KEY `idx_user_behavior_user_time` (`user_id`,`event_time`),
  KEY `idx_user_behavior_event_type_time` (`event_type`,`event_time`),
  KEY `idx_user_behavior_itinerary_time` (`itinerary_id`,`event_time`),
  KEY `idx_user_behavior_poi_time` (`poi_id`,`event_time`),
  KEY `idx_user_behavior_session_time` (`session_id`,`event_time`),
  KEY `idx_user_behavior_request_id` (`request_id`)
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户行为事件事实表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `user_behavior_event`
--

LOCK TABLES `user_behavior_event` WRITE;
/*!40000 ALTER TABLE `user_behavior_event` DISABLE KEYS */;
